#include <bits/stdc++.h>
using namespace std;
const int maxn=16;
double x[maxn],y[maxn],dp[1<<maxn][maxn];
double s(int i,int j){
	return sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j]));
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n;
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>x[i]>>y[i];
	}
	memset(dp,127,sizeof(dp));
	for(int i=0;i<n;i++){
		dp[1<<i][i]=sqrt(x[i]*x[i]+y[i]*y[i]);
	}
	for(int i=1;i<(1<<n);i++){
		for(int j=0;j<n;j++){
			if(!((i>>j)&1)){
				continue;
			}
			for(int k=0;k<n;k++){
				if((i>>k)&1){
					continue;
				}
				int aa=i|(1<<k);
				dp[aa][k]=min(dp[aa][k],dp[i][j]+s(j,k));
			}
		}
	}
	double ans=dp[(1<<n)-1][0];
	for(int i=1;i<n;i++){
		ans=min(ans,dp[(1<<n)-1][i]);
	}
	cout<<fixed<<setprecision(2)<<ans;
	return 0;
}
